{
  "competency_groups": [
    {
      "code": "U5-C1",
      "title": "System of Particles and Rotational Motion",
      "description": "Competencies related to momentum conservation, torque, angular momentum, equilibrium, and rotational motion equations.",
      "competencies": [
        "Apply the law of conservation of linear momentum to analyze centre of mass motion in a system of particles."
      ],
      "unit_name": "Motion of System of Particles and Rigid Body",
      "chapter_name": "System of Particles and Rotational Motion"
    },
    {
      "code": "U6-C1",
      "title": "Gravitation",
      "description": "Competencies related to universal gravitation, variation of gravity, potential energy, orbital mechanics, and Kepler's laws.",
      "competencies": [
        "Apply the Universal Law of Gravitation to calculate gravitational force between masses."
      ],
      "unit_name": "Gravitation",
      "chapter_name": "Gravitation"
    },
    {
      "code": "U7-C1",
      "title": "Mechanical Properties of Solids",
      "description": "Competencies related to elasticity, stress-strain relationships, and material properties like Young's modulus.",
      "competencies": [
        "Apply Hooke's Law to determine the relationship between stress and strain in elastic materials."
      ],
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Solids"
    },
    {
      "code": "U7-C2",
      "title": "Mechanical Properties of Fluids",
      "description": "Competencies related to fluid viscosity, flow dynamics, Bernoulli's theorem, and surface tension phenomena.",
      "competencies": [
        "Apply Stokes' Law and the concept of terminal velocity to analyze motion through viscous fluids."
      ],
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Fluids"
    },
    {
      "code": "U7-C3",
      "title": "Thermal Properties of Matter",
      "description": "Competencies related to heat transfer, specific heats, latent heat, and blackbody radiation laws.",
      "competencies": [
        "Apply the principles of calorimetry and conservation of energy to solve problems involving specific heat capacity."
      ],
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Thermal Properties of Matter"
    }
  ]
}
